import dbConnect from "@/db";
import { Base, Colorant } from "@/db/schema";
import { ensureSeed } from "@/db/seed";

export const dynamic = "force-dynamic";

export async function GET() {
  try {
    await dbConnect();
    await ensureSeed();
    const [baseList, colorantList] = await Promise.all([
      Base.find({}).lean(),
      Colorant.find({}).sort({ sortOrder: 1 }).lean(),
    ]);
    return Response.json({ bases: baseList, colorants: colorantList });
  } catch (error) {
    console.error("[catalog] failed to load", error);
    return Response.json(
      { error: "The colourant catalog could not be loaded." },
      { status: 500 },
    );
  }
}
