let seeded = false;

/** Idempotent seed: inserts catalog + standard formulas only when the tables are empty. */
export async function ensureSeed(): Promise<void> {
  if (seeded) return;
  await dbConnect();
  
  const colorantCount = await Colorant.countDocuments();
  if (colorantCount > 0) {
    seeded = true;
    return;
  }

  await Colorant.insertMany(COLORANT_SEED);
  await Base.insertMany(BASE_SEED);
  await Formula.insertMany(PRESET_SEED);

  seeded = true;
}
